import React, { useState, useEffect } from 'react';
import {
  Box,
  Alert
} from '@mui/material';
import FAWButton from '../../../FAWButton';
import FAWDrawer from '../../../FAWDrawer';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWLoader from '../../../FAWLoader';
import FAWCheckbox from '../../../FAWCheckbox';
import FAWInput from '../../../FAWInput';
import FAWTypography from '../../../FAWTypography';
import { IconButton } from '@mui/material';
import { Add, Remove } from '@mui/icons-material';
import { workflowDefinitionApi } from '../services/workflowDefinitionApi';
import { snippetApi } from '../../snippet/services/snippetApi';

/**
 * Task Settings Drawer Component
 * Handles task settings including required, duration, SLA, notifications, and other options
 */
const TaskSettingsModal = ({ 
  open = false,
  onClose,
  workflowId, // For workflow definition, this is workflowId. For snippet, this is snippetId
  taskId,
  onSave,
  saving: parentSaving = false,
  readOnly = false,
  isSectionTask = false,
  isSnippet = false
}) => {
  const [formData, setFormData] = useState({
    // Essential IDs (use PascalCase to match backend)
    Id: '',
    ContainerId: '',
    // Task settings
    IsRequired: false,
    Duration: 0,
    SLADays: 0,
    SendAlertsTo: '',
    NotificationControls: [],
    IsPhase: false,
    AllowEditTaskName: false,
    // Additional required fields
    Name: '',
    Description: '',
    Type: '',
    Status: '',
    LockId: 1,
    NewlyCreated: false
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [saving, setSaving] = useState(false); // Local saving state

  // Load task data when drawer opens
  useEffect(() => {
    if (open && workflowId && taskId) {
      loadTaskData();
    }
  }, [open, workflowId, taskId]);

  const loadTaskData = async () => {
    setLoading(true);
    setError(null);
    
    try {
      // Use the appropriate API based on whether this is a snippet or workflow definition
      let taskDetail;
      if (isSnippet) {
        // For snippets, workflowId parameter contains the snippetId
        taskDetail = await snippetApi.getTaskDetail(workflowId, taskId);
      } else {
        // For workflow definitions, workflowId is the actual workflowId
        taskDetail = await workflowDefinitionApi.getTaskDetail(workflowId, taskId);
      }
      
      if (taskDetail && taskDetail.data) {
        const taskData = taskDetail.data;
        
        // Deduplicate NotificationControls by TypeCode or Name
        let notificationControls = taskData.NotificationControls || [];
        if (Array.isArray(notificationControls) && notificationControls.length > 0) {
          const seen = new Set();
          notificationControls = notificationControls.filter((control) => {
            // Use TypeCode as primary identifier, fallback to Name if TypeCode doesn't exist
            const identifier = control.TypeCode || control.Name || control.Code;
            if (!identifier) {
              return false; // Filter out items without identifier
            }
            if (seen.has(identifier)) {
              return false; // Duplicate found, filter it out
            }
            seen.add(identifier);
            return true; // Keep this item
          });
        }
        
        setFormData({
          // Use the complete task data structure
          ...taskData,
          // Ensure essential IDs are set correctly (use PascalCase to match backend)
          Id: taskId,
          ContainerId: workflowId,
          // Use deduplicated NotificationControls
          NotificationControls: notificationControls
        });
      } else {
        setError('No task data received from server');
      }
    } catch (err) {
      // Provide more specific error messages
      let errorMessage = 'Failed to load task settings';
      if (err.response) {
        // Server responded with error status
        errorMessage = `Server error: ${err.response.status} - ${err.response.data?.message || 'Unknown error'}`;
      } else if (err.request) {
        // Network error
        errorMessage = 'Network error: Unable to connect to server';
      } else {
        // Other error
        errorMessage = `Error: ${err.message || 'Unknown error occurred'}`;
      }
      
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleFieldChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  // Helper functions for increment/decrement
  const handleIncrement = (field) => {
    const currentValue = formData[field] || 0;
    handleFieldChange(field, Math.max(0, currentValue + 1));
  };

  const handleDecrement = (field) => {
    const currentValue = formData[field] || 0;
    handleFieldChange(field, Math.max(0, currentValue - 1));
  };
  
  const drawerContent = (
    <Box className="task-settings-drawer-container" sx={{ 
      p: 3, 
      position: 'relative',
      display: 'flex',
      flexDirection: 'column',
      gap: 2
    }}>
      {/* Saving overlay */}
      {saving && (
        <Box className="task-settings-drawer-saving-overlay" sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(255, 255, 255, 0.8)',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 1000,
          borderRadius: '8px'
        }}>
          <FAWLoader 
            size={40} 
            label="Saving task settings..." 
            inline={false}
          />
        </Box>
      )}
      
      {loading && (
        <Box className="task-settings-drawer-loading" sx={{ p: 2 }}>
          <FAWSkeleton variant="text" width="100%" height={40} sx={{ mb: 2 }} />
          <FAWSkeleton variant="rectangular" width="100%" height={56} sx={{ mb: 2 }} />
          <FAWSkeleton variant="rectangular" width="100%" height={56} sx={{ mb: 2 }} />
          <FAWSkeleton variant="rectangular" width="100%" height={56} sx={{ mb: 2 }} />
          <FAWSkeleton variant="text" width="60%" height={24} sx={{ mb: 1 }} />
          <FAWSkeleton variant="rectangular" width="100%" height={80} sx={{ mb: 2 }} />
          <FAWSkeleton variant="rectangular" width="100%" height={40} sx={{ mb: 2 }} />
        </Box>
      )}
      
      {error && (
        <Box className="task-settings-drawer-error-state" sx={{ 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center',
          p: 4,
          textAlign: 'center'
        }}>
          <Alert severity="error" sx={{ mb: 3, width: '100%' }}>
            {error}
          </Alert>
          <FAWButton
            variant="contained"
            color="primary"
            onClick={loadTaskData}
            disabled={loading}
            loading={loading}
            sx={{ minWidth: 120 }}
          >
            Retry
          </FAWButton>
        </Box>
      )}
      
      {!loading && !error && (
        <Box className="task-settings-drawer-form" sx={{ p: 1 }}>
          {/* Required Field */}
          <Box className="task-settings-drawer-field task-settings-drawer-required-field" sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
            <FAWCheckbox
              className="task-settings-drawer-checkbox"
              checked={formData.IsRequired || false}
              onChange={(e) => handleFieldChange('IsRequired', e.target.checked)}
              disabled={readOnly}
              sx={{ 
                padding: 0, 
                mr: 1.5,
                '& .MuiSvgIcon-root': {
                  fontSize: '24px'
                }
              }}
            />
            <FAWTypography 
              className="task-settings-drawer-label-text" 
              variant="body2" 
              sx={{ fontSize: '14px', lineHeight: '20px', color: '#282e37' }}
            >
              Required
            </FAWTypography>
          </Box>

          {/* Due Within Field */}
          <Box className="task-settings-drawer-field task-settings-drawer-duration-field" sx={{ display: 'flex', flexDirection: 'column', gap: 1, mb: 2 }}>
            <FAWTypography className="task-settings-drawer-label-text" variant="body2" sx={{ fontWeight: 600, fontSize: '12px', lineHeight: '16px', color: '#282e37' }}>
              Due Within (in days)
            </FAWTypography>
            <Box className="task-settings-drawer-input-with-buttons" sx={{ 
              display: 'flex', 
              alignItems: 'center', 
              backgroundColor: 'white',
              border: '1px solid #6f7377',
              borderRadius: '8px',
              height: '40px',
              px: 1.5,
              py: 1,
              position: 'relative'
            }}>
              <FAWInput
                className="task-settings-drawer-input"
                fullWidth
                type="number"
                value={formData.Duration || 0}
                onChange={(e) => handleFieldChange('Duration', parseInt(e.target.value) || 0)}
                disabled={readOnly}
                size="small"
                sx={{ 
                  '& .MuiOutlinedInput-root': { 
                    height: '24px',
                    border: 'none',
                    '& fieldset': { border: 'none' },
                    '&:hover fieldset': { border: 'none' },
                    '&.Mui-focused fieldset': { border: 'none' }
                  },
                  '& .MuiInputBase-input': {
                    textAlign: 'left !important',
                    fontSize: '16px',
                    color: '#6f7377',
                    paddingRight: '60px' // Add space for buttons
                  }
                }}
              />
              <Box className="task-settings-drawer-buttons" sx={{ 
                display: 'flex', 
                gap: 0.5,
                position: 'absolute',
                right: '8px',
                top: '50%',
                transform: 'translateY(-50%)'
              }}>
                <IconButton
                  size="small"
                  onClick={() => handleDecrement('Duration')}
                  disabled={readOnly}
                  sx={{ 
                    width: '24px', 
                    height: '24px',
                    backgroundColor: '#f5f5f5',
                    '&:hover': { backgroundColor: '#e0e0e0' }
                  }}
                >
                  <Remove sx={{ fontSize: '16px', color: '#666' }} />
                </IconButton>
                <IconButton
                  size="small"
                  onClick={() => handleIncrement('Duration')}
                  disabled={readOnly}
                  sx={{ 
                    width: '24px', 
                    height: '24px',
                    backgroundColor: '#f5f5f5',
                    '&:hover': { backgroundColor: '#e0e0e0' }
                  }}
                >
                  <Add sx={{ fontSize: '16px', color: '#666' }} />
                </IconButton>
              </Box>
            </Box>
          </Box>

          {/* Take Ownership Within Field */}
          <Box className="task-settings-drawer-field task-settings-drawer-sla-field" sx={{ display: 'flex', flexDirection: 'column', gap: 1, mb: 2 }}>
            <FAWTypography className="task-settings-drawer-label-text" variant="body2" sx={{ fontWeight: 600, fontSize: '12px', lineHeight: '16px', color: '#282e37' }}>
              Take Ownership within (in days)
            </FAWTypography>
            <Box className="task-settings-drawer-input-with-buttons" sx={{ 
              display: 'flex', 
              alignItems: 'center', 
              backgroundColor: 'white',
              border: '1px solid #6f7377',
              borderRadius: '8px',
              height: '40px',
              px: 1.5,
              py: 1,
              position: 'relative'
            }}>
              <FAWInput
                className="task-settings-drawer-input"
                fullWidth
                type="number"
                value={formData.SLADays || 0}
                onChange={(e) => handleFieldChange('SLADays', parseInt(e.target.value) || 0)}
                disabled={readOnly}
                size="small"
                sx={{ 
                  '& .MuiOutlinedInput-root': { 
                    height: '24px',
                    border: 'none',
                    '& fieldset': { border: 'none' },
                    '&:hover fieldset': { border: 'none' },
                    '&.Mui-focused fieldset': { border: 'none' }
                  },
                  '& .MuiInputBase-input': {
                    textAlign: 'left !important',
                    fontSize: '16px',
                    color: '#6f7377',
                    paddingRight: '60px' // Add space for buttons
                  }
                }}
              />
              <Box className="task-settings-drawer-buttons" sx={{ 
                display: 'flex', 
                gap: 0.5,
                position: 'absolute',
                right: '8px',
                top: '50%',
                transform: 'translateY(-50%)'
              }}>
                <IconButton
                  size="small"
                  onClick={() => handleDecrement('SLADays')}
                  disabled={readOnly}
                  sx={{ 
                    width: '24px', 
                    height: '24px',
                    backgroundColor: '#f5f5f5',
                    '&:hover': { backgroundColor: '#e0e0e0' }
                  }}
                >
                  <Remove sx={{ fontSize: '16px', color: '#666' }} />
                </IconButton>
                <IconButton
                  size="small"
                  onClick={() => handleIncrement('SLADays')}
                  disabled={readOnly}
                  sx={{ 
                    width: '24px', 
                    height: '24px',
                    backgroundColor: '#f5f5f5',
                    '&:hover': { backgroundColor: '#e0e0e0' }
                  }}
                >
                  <Add sx={{ fontSize: '16px', color: '#666' }} />
                </IconButton>
              </Box>
            </Box>
          </Box>

          {/* Send Alerts To Field */}
          <Box className="task-settings-drawer-field task-settings-drawer-alerts-field" sx={{ display: 'flex', flexDirection: 'column', gap: 1, mb: 2 }}>
            <FAWTypography className="task-settings-drawer-label-text" variant="body2" sx={{ fontWeight: 600, fontSize: '12px', lineHeight: '16px', color: '#282e37' }}>
              Send Alerts to
            </FAWTypography>
            <FAWInput
              className="task-settings-drawer-input"
              fullWidth
              placeholder="example@example.com"
              value={formData.SendAlertsTo || ''}
              onChange={(e) => handleFieldChange('SendAlertsTo', e.target.value)}
              disabled={readOnly}
              error={formData.SendAlertsTo && !validateEmail(formData.SendAlertsTo)}
              helperText={formData.SendAlertsTo && !validateEmail(formData.SendAlertsTo) ? 'Invalid email address' : ''}
              sx={{ 
                '& .MuiOutlinedInput-root': { 
                  height: '40px',
                  backgroundColor: 'white',
                  borderRadius: '8px',
                  '& .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#6f7377'
                  }
                }
              }}
            />
          </Box>

          {/* Notifications To Send Section */}
          <Box className="task-settings-drawer-field task-settings-drawer-notifications-field" sx={{ display: 'flex', flexDirection: 'column', gap: 1, mb: 2 }}>
            <FAWTypography className="task-settings-drawer-label-text" variant="body2" sx={{ fontWeight: 600, fontSize: '12px', lineHeight: '16px', color: '#282e37' }}>
              Notifications To Send
            </FAWTypography>
            <Box className="task-settings-drawer-notifications-container" sx={{ 
              border: '1px solid #6f7377', 
              borderRadius: '8px', 
              p: 1.5,
              backgroundColor: 'white',
              minHeight: '60px'
            }}>
              {formData.NotificationControls && formData.NotificationControls.length > 0 ? (
                formData.NotificationControls.map((control, index) => {
                  // Use TypeCode or Name as key for better React reconciliation
                  const controlKey = control.TypeCode || control.Code || control.Name || `notification-${index}`;
                  return (
                  <Box key={controlKey} className="task-settings-drawer-notification-item" sx={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    py: 1.5,
                    '&:not(:last-child)': { borderBottom: '1px solid #f0f0f0' }
                  }}>
                    <FAWCheckbox
                      className="task-settings-drawer-notification-checkbox"
                      checked={control.Enabled || false}
                      onChange={(e) => {
                        const updatedControls = [...formData.NotificationControls];
                        updatedControls[index] = { ...control, Enabled: e.target.checked };
                        handleFieldChange('NotificationControls', updatedControls);
                      }}
                      disabled={readOnly}
                      sx={{ 
                        padding: 0, 
                        mr: 1.5,
                        '& .MuiSvgIcon-root': {
                          fontSize: '24px'
                        }
                      }}
                    />
                    <FAWTypography 
                      className="task-settings-drawer-notification-label" 
                      variant="body2"
                      sx={{ fontSize: '14px', lineHeight: '20px', color: '#282e37' }}
                    >
                      {control.Name}
                    </FAWTypography>
                  </Box>
                  );
                })
              ) : (
                <Box sx={{ 
                  display: 'flex', 
                  alignItems: 'center', 
                  justifyContent: 'center',
                  py: 2,
                  minHeight: '40px'
                }}>
                  <FAWTypography 
                    variant="body2" 
                    sx={{ 
                      color: '#666666',
                      fontStyle: 'italic',
                      textAlign: 'center'
                    }}
                  >
                    No notification options available
                  </FAWTypography>
                </Box>
              )}
            </Box>
          </Box>

          {/* Treat Section as a Phase (only for section tasks) */}
          {isSectionTask && (
            <Box className="task-settings-drawer-field task-settings-drawer-phase-field" sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
              <Box className="task-settings-drawer-label" sx={{ minWidth: '200px', pr: 2 }}>
                <FAWTypography className="task-settings-drawer-label-text" variant="body2" sx={{ fontWeight: 'bold' }}>Treat Section as a Phase:</FAWTypography>
              </Box>
              <Box className="task-settings-drawer-control" sx={{ flex: 1 }}>
                <FAWCheckbox
                  className="task-settings-drawer-checkbox"
                  checked={formData.IsPhase || false}
                  onChange={(e) => handleFieldChange('IsPhase', e.target.checked)}
                  disabled={readOnly}
                  sx={{ padding: 0 }}
                />
              </Box>
            </Box>
          )}

          {/* Allow Edit Of Task Name */}
          <Box className="task-settings-drawer-field task-settings-drawer-edit-name-field" sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
            <FAWCheckbox
              className="task-settings-drawer-checkbox"
              checked={formData.AllowEditTaskName || false}
              onChange={(e) => handleFieldChange('AllowEditTaskName', e.target.checked)}
              disabled={readOnly}
              sx={{ 
                padding: 0, 
                mr: 1.5,
                '& .MuiSvgIcon-root': {
                  fontSize: '24px'
                }
              }}
            />
            <FAWTypography 
              className="task-settings-drawer-label-text" 
              variant="body2" 
              sx={{ fontSize: '14px', lineHeight: '20px', color: '#282e37' }}
            >
              Allow Edit of Task Name
            </FAWTypography>
          </Box>
        </Box>
      )}
    </Box>
  );

  const handleSave = async () => {
    setSaving(true);
    setError(null);
    
    try {
      const result = await onSave(formData);
      
      // Only close drawer if save was successful
      if (result && result.success) {
        onClose();
      } else {
        // If save failed, show error
        setError(result?.message || 'Save failed');
      }
    } catch (error) {
      setError(error.message || 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  // Define drawer actions for proper footer
  const drawerActions = [
    {
      text: 'Cancel',
      variant: 'outlined',
      color: 'inherit',
      onClick: onClose,
      disabled: saving
    },
    {
      text: 'Save',
      variant: 'contained',
      onClick: handleSave,
      disabled: readOnly || saving || error, // Disable save when there's an error
      loading: saving,
      handlerType: 'custom', // Tell FAWDrawer to use custom handler instead of form submission
      bypassFormSubmit: true // Bypass form submission logic
    }
  ];

  return (
    <FAWDrawer
      className="task-settings-drawer"
      open={open}
      onClose={onClose}
      title="Task Settings"
      width={500}
      anchor="right"
      showCloseButton={true}
      showHeader={true}
      customFooter={true}
      actions={drawerActions}
    >
      {drawerContent}
    </FAWDrawer>
  );
};

// Email validation helper function
const validateEmail = (email) => {
  const emailReg = /^([\w-\.]+@([\w-]+\.)+[\w-]{2,4})?$/;
  return emailReg.test(email);
};

export default TaskSettingsModal;
